ENTRY.C_REF_NUMBER:
var type;
  var cash=DV.getCurrentDoData('MUL_CASH_IND');
  if (cash.equals('No')){
    type =DV.getCurrentDoData('CPYT_DR_AC_TYPE');
  }else{
    type ='BANK';
  }
  DV.appendField(type);

ENTRY.C_VCH_SPECIAL1:
var title;
  var cash=DV.getCurrentDoData('MUL_CASH_IND');
  if (cash.equals('No')){
    title =DV.getCurrentDoData('CPYT_DR_NAME');
  }else{
    title ='SETTLEMENT SUSPENSE';
  }
  DV.appendField(title);

ENTRY.C_TRANS_CODE:
var vatInd = DV.getFieldValue("VAT_IND1");
DV.writeLog("vatInd got "+vatInd);
if (vatInd != null){
	DV.appendField(vatInd);
}else{
	DV.appendField("N");
}
